import{_ as e,o as i,c as a,ag as o}from"./chunks/framework.CXIqMST4.js";const p=JSON.parse('{"title":"排障手册","description":"","frontmatter":{},"headers":[],"relativePath":"guide/09-troubleshooting.md","filePath":"guide/09-troubleshooting.md","lastUpdated":1777684488000}'),t={name:"guide/09-troubleshooting.md"};function r(d,l,n,h,u,s){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="排障手册" tabindex="-1">排障手册 <a class="header-anchor" href="#排障手册" aria-label="Permalink to &quot;排障手册&quot;">​</a></h1><p>本页收集 Codex 使用中的常见问题。欢迎通过 PR 持续补充。</p><h2 id="codex-找不到项目上下文" tabindex="-1">Codex 找不到项目上下文 <a class="header-anchor" href="#codex-找不到项目上下文" aria-label="Permalink to &quot;Codex 找不到项目上下文&quot;">​</a></h2><p>可能原因：</p><ul><li>你不在项目根目录。</li><li>仓库缺少 README、测试命令或项目说明。</li><li>monorepo 没有说明包边界。</li></ul><p>处理方式：</p><ul><li>先让 Codex 只读目录并总结项目结构。</li><li>添加或更新 <code>AGENTS.md</code>。</li><li>在任务说明里指定相关目录。</li></ul><h2 id="codex-改动范围太大" tabindex="-1">Codex 改动范围太大 <a class="header-anchor" href="#codex-改动范围太大" aria-label="Permalink to &quot;Codex 改动范围太大&quot;">​</a></h2><p>处理方式：</p><ul><li>明确“只修改这些文件”。</li><li>要求“先输出计划，不要动手”。</li><li>把任务拆成更小的步骤。</li><li>在 review 时拒绝无关重构。</li></ul><h2 id="测试跑不起来" tabindex="-1">测试跑不起来 <a class="header-anchor" href="#测试跑不起来" aria-label="Permalink to &quot;测试跑不起来&quot;">​</a></h2><p>处理方式：</p><ul><li>让 Codex 先定位测试命令。</li><li>检查依赖是否安装。</li><li>区分环境问题和代码问题。</li><li>如果是环境问题，让 Codex 记录阻塞，而不是继续乱改。</li></ul><h2 id="生成内容不准确" tabindex="-1">生成内容不准确 <a class="header-anchor" href="#生成内容不准确" aria-label="Permalink to &quot;生成内容不准确&quot;">​</a></h2><p>处理方式：</p><ul><li>要求 Codex 引用它依据的文件。</li><li>对官方事实要求附链接。</li><li>让它区分“已确认”和“推测”。</li><li>让它先读代码再写文档。</li></ul><h2 id="登录或权限问题" tabindex="-1">登录或权限问题 <a class="header-anchor" href="#登录或权限问题" aria-label="Permalink to &quot;登录或权限问题&quot;">​</a></h2><p>处理方式：</p><ul><li>更新 Codex CLI 到最新版本。</li><li>重新运行登录流程。</li><li>检查当前账号计划和组织策略。</li><li>查看官方 Help Center 的 Codex 相关文章。</li></ul>',19)])])}const x=e(t,[["render",r]]);export{p as __pageData,x as default};
